enum Nested {
    Num(i32),
    List(Vec<Nested>),
}

fn flatten_deep(items: &[Nested]) -> Vec<i32> {
    // Your code here
    Vec::new()
}

solution.code:
enum Nested {
    Num(i32),
    List(Vec<Nested>),
}

fn flatten_deep(items: &[Nested]) -> Vec<i32> {
    fn walk(items: &[Nested], out: &mut Vec<i32>) {
        for item in items {
            match item {
                Nested::Num(n) => out.push(*n),
                Nested::List(inner) => walk(inner, out),
            }
        }
    }

    let mut out = Vec::new();
    walk(items, &mut out);
    out
}

